import{_ as r,C as n,o as t,c as i,a0 as a,b as l,w as o,a as d,E as c,a1 as p}from"./chunks/framework.DZNqfkJl.js";const C=JSON.parse('{"title":"Frontend Setup and Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"en/frontend.md","filePath":"en/frontend.md"}'),u={name:"en/frontend.md"};function h(g,e,m,f,b,v){const s=n("Mermaid");return t(),i("div",null,[e[1]||(e[1]=a('<h1 id="frontend-setup-and-architecture" tabindex="-1">Frontend Setup and Architecture <a class="header-anchor" href="#frontend-setup-and-architecture" aria-label="Permalink to &quot;Frontend Setup and Architecture&quot;">​</a></h1><p>The <strong>Structo</strong> frontend is built using <strong>Nuxt 4</strong>, which runs on top of <strong>Vue 3</strong>. Nuxt provides a robust architecture by default, supporting Server-Side Rendering (SSR) or Static Site Generation (SSG) while naturally structuring the codebase.</p><h2 id="🚀-how-to-run-locally" tabindex="-1">🚀 How to Run Locally <a class="header-anchor" href="#🚀-how-to-run-locally" aria-label="Permalink to &quot;🚀 How to Run Locally&quot;">​</a></h2><h3 id="_1-install-dependencies" tabindex="-1">1. Install Dependencies <a class="header-anchor" href="#_1-install-dependencies" aria-label="Permalink to &quot;1. Install Dependencies&quot;">​</a></h3><p>Make sure you have Node.js (22 or higher) installed. Open your terminal, navigate to the frontend project, and install all dependencies:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span></code></pre></div><h3 id="_2-environment-variables" tabindex="-1">2. Environment Variables <a class="header-anchor" href="#_2-environment-variables" aria-label="Permalink to &quot;2. Environment Variables&quot;">​</a></h3><p>Ensure you have configured the correct environments by reviewing or adjusting the respective file for local development. Nuxt 4 natively reads variables from <code>.env</code>.</p><h3 id="_3-start-the-development-server" tabindex="-1">3. Start the Development Server <a class="header-anchor" href="#_3-start-the-development-server" aria-label="Permalink to &quot;3. Start the Development Server&quot;">​</a></h3><p>To run the application with Hot Module Replacement (HMR):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>The web application will typically be served at <code>http://localhost:3000</code>.</p><hr><h2 id="🏗️-applied-patterns-and-ecosystem" tabindex="-1">🏗️ Applied Patterns and Ecosystem <a class="header-anchor" href="#🏗️-applied-patterns-and-ecosystem" aria-label="Permalink to &quot;🏗️ Applied Patterns and Ecosystem&quot;">​</a></h2><ul><li><strong>Strict Typescript</strong>: All core code, <code>stores</code>, and requests are strongly typed (TypeScript) to prevent runtime errors.</li><li><strong>Vuetify (UI Library)</strong>: <strong>Vuetify</strong> is heavily utilized as the main visual component framework (Material Design), providing a complete ecosystem of adaptive buttons, tables, grids, and directives.</li><li><strong>Pinia for State Management</strong>: Replaces Vuex. Used in the <code>stores/</code> folder to manage transparent and reactive global data flows throughout the application.</li><li><strong>Composables</strong>: Extensive use of the Vue 3 Composition API (<code>setup()</code>). Composables allow you to extract reusable logic and state into pages or components.</li><li><strong>Shared Auto-imports</strong>: Nuxt 4 auto-imports components, composables, and utilities by default, saving you from having to clutter the explicit imports section.</li></ul><h2 id="📁-directory-structure" tabindex="-1">📁 Directory Structure <a class="header-anchor" href="#📁-directory-structure" aria-label="Permalink to &quot;📁 Directory Structure&quot;">​</a></h2><p>The structure under the <code>frontend/app</code> folder follows Nuxt&#39;s conventional File-System Routing standard:</p>',17)),(t(),l(p,null,{default:o(()=>[c(s,{id:"mermaid-69",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20P%5Bpages%2F%5CnFile-based%20Routing%5D%20--%3E%20C%7Bcomponents%2F%5CnUI%20Components%7D%0A%20%20%20%20P%20--%3E%20COMP%5Bcomposables%2F%5CnReusable%20Vue%203%20Logic%5D%0A%20%20%20%20P%20--%3E%20S%5Bstores%2F%5CnPinia%20State%20Management%5D%0A%20%20%20%20%0A%20%20%20%20C%20--%3E%20COMP%0A%20%20%20%20C%20--%3E%20S%0A%20%20%20%20COMP%20-.%20API%20Request%20.-%3E%20API((Backend%20Ecosystem))%0A%20%20%20%20S%20-.%20Local%20Hydration%20.-%3E%20COMP%0A%20%20%20%20%0A%20%20%20%20style%20P%20fill%3A%2300DC82%2Cstroke%3A%23000%2Cstroke-width%3A2px%2Ccolor%3A%23000%0A%20%20%20%20style%20C%20fill%3A%2334495e%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20COMP%20fill%3A%2342b883%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20S%20fill%3A%23ffe12b%2Cstroke%3A%23a68e00%2Cstroke-width%3A2px%2Ccolor%3A%23000%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[d(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h3 id="app-main-directories-description" tabindex="-1">App Main Directories Description <a class="header-anchor" href="#app-main-directories-description" aria-label="Permalink to &quot;App Main Directories Description&quot;">​</a></h3><ul><li><strong>app.vue</strong>: The main component and visual entry point of the application.</li><li><strong>pages/</strong>: Hosts the <em>View</em> components. Each <code>.vue</code> file within this directory graphically represents a different web route.</li><li><strong>components/</strong>: Used for modular and reusable visual components. Nuxt will register them automatically around the project.</li><li><strong>layouts/</strong>: Allows setting common graphical shells (navbar, footer, sidebar, etc.) to be shared between different <code>pages</code>.</li><li><strong>composables/</strong>: Hosts exported functions (like <code>useMyLogic()</code>). Ideal for direct fetch requests, logical state, and form utilities.</li><li><strong>stores/</strong>: Defines the <strong>Pinia</strong> stores. Centralized data logic (e.g., the current user session, active cart, etc.).</li><li><strong>middleware/</strong>: Code that executes <em>before</em> transitioning to a particular route. (Ideal for authentication guards).</li><li><strong>plugins/</strong>: Global code that loads to initialize extra tools inside the Vue instance before rendering.</li><li><strong>public/</strong> and <strong>assets/</strong>: For static images, web fonts, or global stylesheets (like CSS/SCSS).</li></ul>',2))])}const A=r(u,[["render",h]]);export{C as __pageData,A as default};
